import { A as AuroInput } from './auro-input.min.js';
import { c as customError, s as setReadonlyValue, a as swapInputValues, r as resetStateExample } from './swap-value.min.js';

AuroInput.register();
AuroInput.register('custom-input');

function initExamples(initCount) {
  initCount = initCount || 0;

  try {
    customError();
    setReadonlyValue();
    swapInputValues();
    resetStateExample();
  } catch (error) {
    if (initCount <= 20) {
      setTimeout(() => {
        initExamples(initCount + 1);
      }, 100);
    }
  }
}

export { initExamples };
